#include <iostream>
#include <unordered_set>

using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

bool hasCycle(ListNode *head)
{
    unordered_set<ListNode*> visited;

    for (ListNode* n = head; n; n = n->next)
    {
        if (visited.count(n)) return true;
        visited.insert(n);
    }

    return false;
}

