#include <iostream>

using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

ListNode* detectCycle(ListNode *head)
{
    ListNode* slow = head;
    ListNode* fast = head;

    while (fast != nullptr && fast->next != nullptr)
    {
        slow = slow->next;
        fast = fast->next->next;

        if (slow == fast)
        {
            ListNode* pointer = head;
            while (pointer != slow)
            {
                pointer = pointer->next;
                slow = slow->next;
            }
            return pointer;
        }
    }

    return nullptr;
}

int main()
{
    ListNode* a = new ListNode(3);
    ListNode* b = new ListNode(2);
    ListNode* c = new ListNode(0);
    ListNode* d = new ListNode(-4);
    a->next = b; b->next = c; c->next = d; d->next = b;

    ListNode* result = detectCycle(a);
    cout << (result ? result->val : -1) << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

struct Node {
    int val;
    Node* next;
    Node(int v) : val(v), next(nullptr) {}
};

Node* insert(Node* head, int insertVal)
{
    vector<int> values;
    if (head != nullptr)
    {
        Node* cur = head;
        do { values.push_back(cur->val); cur = cur->next; } while (cur != head);
    }
    values.push_back(insertVal);
    sort(values.begin(), values.end());

    Node* newHead = new Node(values[0]);
    Node* tail = newHead;
    for (int i = 1; i < values.size(); i++)
    {
        tail->next = new Node(values[i]);
        tail = tail->next;
    }
    tail->next = newHead;

    return newHead;
}

int main()
{
    Node* a = new Node(3);
    Node* b = new Node(4);
    Node* c = new Node(1);
    a->next = b; b->next = c; c->next = a;

    Node* result = insert(a, 2);
    Node* cur = result;
    do { cout << cur->val << " "; cur = cur->next; } while (cur != result);

    return 0;
}

#include <iostream>

using namespace std;

struct Node {
    int val;
    Node* next;
    Node(int v) : val(v), next(nullptr) {}
};

Node* insert(Node* head, int insertVal)
{
    Node* newNode = new Node(insertVal);

    if (head == nullptr)
    {
        newNode->next = newNode;
        return newNode;
    }

    Node* prev = head;
    Node* curr = head->next;

    while (curr != head)
    {
        if (prev->val <= insertVal && insertVal <= curr->val) break; // normal case
        if (prev->val > curr->val && (insertVal >= prev->val || insertVal <= curr->val)) break; // wraparound
        prev = curr;
        curr = curr->next;
    }

    prev->next = newNode;
    newNode->next = curr;

    return head;
}

int main()
{
    Node* a = new Node(3);
    Node* b = new Node(4);
    Node* c = new Node(1);
    a->next = b; b->next = c; c->next = a;

    Node* result = insert(a, 2);
    Node* cur = result;
    do { cout << cur->val << " "; cur = cur->next; } while (cur != result);

    return 0;
}

